mapper.select:
select

from stat_battery_pack pack


        and pack.config_id = #{configId}


        and pack.pack_num = #{packNum}



        and strftime('%Y-%m-%d %H:%M:%S', pack.create_time) >= strftime('%Y-%m-%d %H:%M:%S',
        #{params.beginTime})



        and strftime('%Y-%m-%d %H:%M:%S', pack.create_time) <= strftime('%Y-%m-%d %H:%M:%S',
        #{params.endTime})


order by create_time ${isAsc}

mapper.delete:
delete
from stat_battery_pack
where config_id = #{configId}

    and pack_num = #{packNum}

mapper.select:
select avg(t.pack_current) as current from stat_battery_pack t
and t.pack_num = #{packNum}
and strftime('%Y-%m-%d %H:%M:%S', t.create_time) >= strftime('%Y-%m-%d %H:%M:%S', #{params.beginTime})
and strftime('%Y-%m-%d %H:%M:%S', t.create_time) <= strftime('%Y-%m-%d %H:%M:%S', #{params.endTime})
and config_id = #{configId}

select count() from stat_battery_pack pack
and pack.config_id = #{configId}
and pack.pack_num = #{packNum}
and strftime('%Y-%m-%d %H:%M:%S', pack.create_time) >= strftime('%Y-%m-%d %H:%M:%S', #{params.beginTime})
and strftime('%Y-%m-%d %H:%M:%S', pack.create_time) <= strftime('%Y-%m-%d %H:%M:%S', #{params.endTime})
